import hmac
import hashlib
import base64
import struct
import time
import secrets
import qrcode
from io import BytesIO
from typing import Optional, Tuple


class TOTP:
    def __init__(self, secret: Optional[str] = None, interval: int = 30, digits: int = 6, 
                 algorithm: str = 'sha1'):
        if secret is None:
            self.secret = self.generate_secret()
        else:
            self.secret = secret
        self.interval = interval
        self.digits = digits
        self.algorithm = algorithm.lower()
    
    @staticmethod
    def generate_secret(length: int = 32) -> str:
        random_bytes = secrets.token_bytes(length)
        return base64.b32encode(random_bytes).decode('utf-8').rstrip('=')
    
    def _get_hotp(self, counter: int) -> str:
        hash_algos = {
            'sha1': hashlib.sha1,
            'sha256': hashlib.sha256,
            'sha512': hashlib.sha512
        }
        
        hash_func = hash_algos.get(self.algorithm, hashlib.sha1)
        
        key = base64.b32decode(self.secret + '=' * ((8 - len(self.secret)) % 8))
        
        counter_bytes = struct.pack('>Q', counter)
        
        hmac_hash = hmac.new(key, counter_bytes, hash_func).digest()
        
        offset = hmac_hash[-1] & 0x0F
        
        truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF
        
        otp = truncated % (10 ** self.digits)
        
        return str(otp).zfill(self.digits)
    
    def get_current_time_counter(self, timestamp: Optional[float] = None) -> int:
        if timestamp is None:
            timestamp = time.time()
        return int(timestamp // self.interval)
    
    def generate_totp(self, timestamp: Optional[float] = None) -> str:
        counter = self.get_current_time_counter(timestamp)
        return self._get_hotp(counter)
    
    def verify_totp(self, token: str, timestamp: Optional[float] = None, 
                    window: int = 1) -> bool:
        if timestamp is None:
            timestamp = time.time()
        
        current_counter = self.get_current_time_counter(timestamp)
        
        for i in range(-window, window + 1):
            counter = current_counter + i
            expected_token = self._get_hotp(counter)
            if hmac.compare_digest(expected_token, token):
                return True
        
        return False
    
    def get_provisioning_uri(self, account_name: str, issuer_name: str) -> str:
        params = f'secret={self.secret}&issuer={issuer_name}&algorithm={self.algorithm.upper()}&digits={self.digits}&period={self.interval}'
        uri = f'otpauth://totp/{issuer_name}:{account_name}?{params}'
        return uri
    
    def generate_qr_code(self, account_name: str, issuer_name: str, 
                        format: str = 'PNG') -> BytesIO:
        uri = self.get_provisioning_uri(account_name, issuer_name)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        buffer = BytesIO()
        img.save(buffer, format=format)
        buffer.seek(0)
        
        return buffer


class TOTPAuthenticator:
    def __init__(self):
        self.users = {}
    
    def register_user(self, username: str, interval: int = 30, 
                     digits: int = 6) -> Tuple[str, str]:
        totp = TOTP(interval=interval, digits=digits)
        self.users[username] = totp
        return totp.secret, totp.generate_totp()
    
    def get_user_totp(self, username: str) -> Optional[TOTP]:
        return self.users.get(username)
    
    def verify_user_token(self, username: str, token: str, 
                         window: int = 1) -> bool:
        totp = self.users.get(username)
        if totp is None:
            return False
        return totp.verify_totp(token, window=window)
    
    def generate_qr_code_for_user(self, username: str, issuer_name: str, 
                                  format: str = 'PNG') -> Optional[BytesIO]:
        totp = self.users.get(username)
        if totp is None:
            return None
        return totp.generate_qr_code(username, issuer_name, format)
    
    def remove_user(self, username: str) -> bool:
        if username in self.users:
            del self.users[username]
            return True
        return False


